import { expect } from "chai";
import chunk from "../src/chunk.js";

describe("chunk", () => {
  it("should split array into chunks of given size", () => {
    const array = [1, 2, 3, 4, 5];
    const size = 2;
    const result = chunk(array, size);
    expect(result).to.deep.equal([[1, 2], [3, 4], [5]]);
  });

  it("should handle size larger than array length", () => {
    const array = [1, 2, 3];
    const size = 5;
    const result = chunk(array, size);
    expect(result).to.deep.equal([[1, 2, 3]]);
  });

  it("should handle size 0 or negative by returning empty array", () => {
    expect(chunk([1, 2, 3], 0)).to.deep.equal([]);
    expect(chunk([1, 2, 3], -1)).to.deep.equal([]);
  });

  it("should handle empty array", () => {
    expect(chunk([], 2)).to.deep.equal([]);
  });

  it("should handle undefined size explicitly", () => {
    // Nykyinen toteutus ei oikein tue oletuskokoa, mutta annetaan size=1
    const array = [1, 2, 3];
    const result = chunk(array, 1);
    expect(result).to.deep.equal([[1], [2], [3]]);
  });
});
